import { Component, OnInit } from '@angular/core';

import {
  ActivatedRoute,
  Router
} from '@angular/router';

import { FarmerService } from 'src/app/core/services/farmer.service';

@Component({
  selector: 'app-edit-farmer',
  templateUrl: './edit-farmer.component.html'
})
export class EditFarmerComponent
  implements OnInit {

  farmerId = 0;

  farmer = {
    name: '',
    mobile: '',
    village: '',
    state: '',
    landArea: 0
  };

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private farmerService: FarmerService
  ) {
  }

  ngOnInit(): void {

    this.farmerId =
      Number(this.route.snapshot.paramMap.get('id'));

    this.loadFarmer();
  }

  loadFarmer() {

    this.farmerService
      .getFarmers()
      .subscribe((response: any) => {

        const data =
          response.data.find(
            (x: any) => x.id == this.farmerId);

        this.farmer = data;
      });
  }

  updateFarmer() {

    this.farmerService
      .updateFarmer(
        this.farmerId,
        this.farmer)
      .subscribe((response: any) => {

        if (response.success) {

          alert('Farmer updated');

          this.router.navigate(['/farmers']);
        }
      });
  }
}
<app-navbar></app-navbar>

<div class="container mt-4">

  <div class="card p-4">

    <h3 class="mb-4">
      Edit Farmer
    </h3>

    <div class="row">

      <div class="col-md-6 mb-3">

        <label>Name</label>

        <input type="text"
               class="form-control"
               [(ngModel)]="farmer.name">

      </div>

      <div class="col-md-6 mb-3">

        <label>Mobile</label>

        <input type="text"
               class="form-control"
               [(ngModel)]="farmer.mobile">

      </div>

      <div class="col-md-6 mb-3">

        <label>Village</label>

        <input type="text"
               class="form-control"
               [(ngModel)]="farmer.village">

      </div>

      <div class="col-md-6 mb-3">

        <label>State</label>

        <input type="text"
               class="form-control"
               [(ngModel)]="farmer.state">

      </div>

      <div class="col-md-6 mb-3">

        <label>Land Area</label>

        <input type="number"
               class="form-control"
               [(ngModel)]="farmer.landArea">

      </div>

    </div>

    <button class="btn btn-success"
            (click)="updateFarmer()">

      Update Farmer
    </button>

  </div>

</div>
